prompts.prompt:
clear all;
close all;

% Pfad zu Ihrem Datenverzeichnis
dataDir = 'D:\Versuche\Berg_Mitte_Gecutted';

% Manuelle Eingabe der Messungsnummern
measurements = [7]; % Fügen Sie hier die Nummern der Messungen ein, die Sie plotten möchten

% Messsystem bleibt standard als A
measurementSystem = 'A';

numPlots = 10; % Anzahl der gewünschten Plots

% Latex-Einstellungen
set(0, 'defaultTextInterpreter', 'latex');
set(gca, 'TickLabelInterpreter', 'latex');

for measurementNumber = measurements
% Erstelle den Dateinamen basierend auf den extrahierten Informationen
matFile = fullfile(dataDir, [measurementSystem '2#' sprintf('%03d', measurementNumber) '.mat']);

% Lade die gespeicherten Daten
loadedData = load(matFile);
cut_F = loadedData.cut_F;

% Anzahl der Zeitschritte in cut_F
numTimeSteps = size(cut_F, 1);
numDataPoints = size(cut_F, 2);

% Schrittweite für die Plots
stepSize = floor(numTimeSteps / numPlots);

% Erzeuge eine Figur
figure('Name', ['Measurement ' num2str(measurementNumber)], 'NumberTitle', 'off');
hold on;

% Plot-Erstellung
for i = 1:numPlots
timeIndex = (i - 1) * stepSize + 1;
signal = cut_F(timeIndex, :);

% Plotten des Signals ohne Normalisierung
plot(1:numDataPoints, signal, 'LineWidth', 2, 'DisplayName', ['Time Step ' num2str(timeIndex)]);

end

hold off;
xlabel('Data Points', 'Interpreter', 'latex');
ylabel('Values', 'Interpreter', 'latex');
title(['Messung ' num2str(measurementNumber) ' - Verschiedene Zeitpunkte'], 'Interpreter', 'latex');
legend('Location', 'southeast', 'Interpreter', 'latex');
grid on;

% Bildgröße und Schriftgröße anpassen
set(gcf, 'Units', 'Centimeters', 'OuterPosition', [15, 5, 20, 20 * 0.8]);
set(gca, 'FontName', 'Frontpage', 'FontSize', 11);

end

